import { Fixture } from "../../objects/fixture";
import  { GetGlsFor, GetGlsAgainst } from "../../utils/fixture-utils";

interface SeasonSummaryComponentProps{
    fixtures : Fixture[],
    gameType : number
}

const SeasonSummary = (seasonSummary : SeasonSummaryComponentProps) => {  

    const totalGames = fixtures.length;
    const totalWins = fixtures.filter(fixture => fixture.result === 0).length;
    const totalDraws = fixtures.filter(fixture => fixture.result === 1).length;
    const totalLosses = fixtures.filter(fixture => fixture.result === 2).length;
    const glsFor = GetGlsFor({fixtures : fixtures, gameType : 0});    
    const glsAgainst = GetGlsAgainst({fixtures : fixtures, gameType : 0});
    const goalDifference = glsFor - glsAgainst;
    const totalPoints = fixtures.filter(fixture => fixture.pts).reduce((sum, currentValue) => sum + currentValue.pts, 0);

    return (         
        <div className = 'row'>
            <div className='col-1'></div> 
            <div className='col-10'>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <td>PLD</td>
                            <td>W</td>
                            <td>L</td>
                            <td>D</td>
                            <td>GF</td>
                            <td>GA</td>
                            <td>GD</td>
                            <td>Pts</td>
                        </tr>
                    </thead>
                    <tbody>
                    <tr>
                        <td>{totalGames}</td>
                        <td>{totalWins}</td>
                        <td>{totalDraws}</td>
                        <td>{totalLosses}</td>
                        <td>{glsFor}</td>     
                        <td>{glsAgainst}</td>       
                        <td>{goalDifference}</td>
                        <td>{totalPoints}</td>
                    </tr>  
                    </tbody>        
                </table>
            </div>  
        </div>        
    );

}
export default SeasonSummary;
